.tip {
  padding: 6px 20px;
  position: relative;
  color: #fff;
  margin-bottom: 20px;
  background: linear-gradient(90deg, #41363c, #494648);
  padding: 6px 20px;
  border-radius: 10px;
  box-shadow: 0 3px 5px rgba(50,50,50,0.5);
}
.tip p {
  margin: 0 !important;
  padding: 0.5rem 0;
}
.tip:before {
  background: linear-gradient(0deg, #41363c, #494648);
  text-shadow: 0 -1px #41363c;
  border-radius: 50%;
  color: #fff;
  font-size: 12px;
  position: absolute;
  width: 24px;
  height: 24px;
  line-height: 24.5px;
  left: -12px;
  top: -12px;
  box-shadow: 0 0 0 2.5px #f7f8f9;
